SELECT ?ethnicGroup (SAMPLE(?ethnicGroupLabel) AS ?ethnicGroupLabel) ?population (GROUP_CONCAT(?religionLabel; separator=", ") AS ?religions) (GROUP_CONCAT(?languageLabel; separator=", ") AS ?languages) (GROUP_CONCAT(?countryLabel; separator=", ") AS ?countries)
WHERE {
  ?ethnicGroup wdt:P31/wdt:P279* wd:Q2412133;
               wdt:P17 ?country;
               wdt:P1082 ?population.

  ?country wdt:P31 wd:Q6256;
           wdt:P131 wd:Q4412.

  ?ethnicGroup rdfs:label ?ethnicGroupLabel FILTER (lang(?ethnicGroupLabel) = "en").
  ?country rdfs:label ?countryLabel FILTER (lang(?countryLabel) = "en").

  OPTIONAL {
    ?ethnicGroup wdt:P140 ?religion.
    ?religion rdfs:label ?religionLabel FILTER (lang(?religionLabel) = "en").
  }
  OPTIONAL {
    ?ethnicGroup wdt:P149 ?language.
    ?language rdfs:label ?languageLabel FILTER (lang(?languageLabel) = "en").
  }

  FILTER (?population > 0)
}
GROUP BY ?ethnicGroup ?population
ORDER BY DESC(?population)
LIMIT 5

SELECT ?ethnicGroup ?ethnicGroupLabel ?population
WHERE {
  ?ethnicGroup wdt:P31/wdt:P279* wd:Q2412133;
